INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A1_01','story','/ˈstɔːri/','noun','이야기','A description of events, real or imagined.','She told us a {story} before bed.','그녀는 자기 전에 우리에게 이야기를 해줬어요.','story','A1','humanities',1,'book open story reading'),
('w_humanities_A1_02','book','/bʊk/','noun','책','A written work published in printed or digital form.','I read a {book} every month.','저는 매달 책을 한 권 읽어요.','book','A1','humanities',1,'book shelf library read'),
('w_humanities_A1_03','read','/riːd/','verb','읽다','To look at and understand written words.','Do you like to {read} in the morning?','아침에 독서하는 걸 좋아하세요?','read','A1','humanities',1,'person reading book open'),
('w_humanities_A1_04','write','/raɪt/','verb','쓰다','To mark words or symbols on a surface.','She loves to {write} short stories.','그녀는 단편 소설 쓰는 것을 좋아해요.','write','A1','humanities',1,'pen paper writing notebook'),
('w_humanities_A1_05','poem','/ˈpoʊɪm/','noun','시','A piece of writing in verse, often with rhythm.','He read a beautiful {poem} at the ceremony.','그는 행사에서 아름다운 시를 낭독했어요.','poem','A1','humanities',2,'poetry book writing verse'),
('w_humanities_A1_06','song','/sɒŋ/','noun','노래','A short piece of music with words.','She wrote a {song} about her hometown.','그녀는 고향에 대한 노래를 썼어요.','song','A1','humanities',1,'music notes singing guitar'),
('w_humanities_A1_07','history','/ˈhɪstəri/','noun','역사','The study of past events.','We studied the {history} of ancient civilizations.','우리는 고대 문명의 역사를 공부했어요.','history','A1','humanities',1,'ancient history books archive'),
('w_humanities_A1_08','old','/oʊld/','adjective','오래된','Having existed or lived for a long time.','This is an {old} and famous novel.','이것은 오래되고 유명한 소설이에요.','old','A1','humanities',2,'old books vintage library'),
('w_humanities_A1_09','people','/ˈpiːpəl/','noun','사람들','Human beings in general.','{People} love stories that feel real.','사람들은 현실적으로 느껴지는 이야기를 좋아해요.','people','A1','humanities',1,'crowd people gathering social'),
('w_humanities_A1_10','word','/wɜːrd/','noun','단어','A single unit of language.','What does this {word} mean in English?','이 단어는 영어로 무슨 뜻이에요?','word','A1','humanities',1,'dictionary words letters text'),
('w_humanities_A1_11','name','/neɪm/','noun','이름','A word used to identify a person or thing.','What is the {name} of this poem?','이 시의 제목이 뭐예요?','name','A1','humanities',2,'name tag label identity'),
('w_humanities_A1_12','page','/peɪdʒ/','noun','페이지','One side of a sheet of paper in a book.','Open your book to {page} ten.','책의 10페이지를 펴세요.','page','A1','humanities',2,'book page open reading'),
('w_humanities_A1_13','picture','/ˈpɪktʃər/','noun','그림, 사진','A drawing, painting, or photograph.','There is a {picture} in every chapter.','모든 챕터에 그림이 있어요.','picture','A1','humanities',2,'illustration art painting book'),
('w_humanities_A1_14','letter','/ˈletər/','noun','편지; 글자','A written message sent to someone; a symbol in an alphabet.','She wrote a long {letter} to her friend.','그녀는 친구에게 긴 편지를 썼어요.','letter','A1','humanities',2,'letter envelope pen writing'),
('w_humanities_A1_15','learn','/lɜːrn/','verb','배우다','To gain knowledge or a skill through study or experience.','We {learn} new words by reading books.','우리는 독서를 통해 새 단어를 배워요.','learn','A1','humanities',1,'study learning book education'),
('w_humanities_A1_16','love','/lʌv/','noun','사랑; 좋아함','An intense feeling of affection; great enjoyment.','Her {love} for literature started early.','그녀의 문학에 대한 사랑은 일찍 시작됐어요.','love','A1','humanities',1,'heart love passion books'),
('w_humanities_A1_17','life','/laɪf/','noun','삶, 인생','The existence of a human being.','Good novels reflect real {life}.','좋은 소설은 현실의 삶을 반영해요.','life','A1','humanities',1,'life journey human nature'),
('w_humanities_A1_18','title','/ˈtaɪtəl/','noun','제목','The name of a book, film, or other work.','What is the {title} of your favorite book?','가장 좋아하는 책의 제목이 뭐예요?','title','A1','humanities',2,'book cover title label'),
('w_humanities_A1_19','question','/ˈkwɛstʃən/','noun','질문','A sentence asking for information.','The author raises an important {question}.','작가는 중요한 질문을 제기해요.','question','A1','humanities',2,'question mark thinking wonder'),
('w_humanities_A1_20','think','/θɪŋk/','verb','생각하다','To have thoughts or opinions about something.','What do you {think} about the ending?','결말에 대해 어떻게 생각하세요?','think','A1','humanities',1,'thinking reflection idea mind'),
('w_humanities_A1_21','true','/truː/','adjective','사실인, 진짜의','In accordance with fact or reality.','The story is based on {true} events.','그 이야기는 실제 사건을 바탕으로 해요.','true','A1','humanities',2,'truth reality fact document'),
('w_humanities_A1_22','beautiful','/ˈbjuːtɪfəl/','adjective','아름다운','Pleasing to the senses or mind.','She wrote a {beautiful} poem for the class.','그녀는 수업을 위해 아름다운 시를 썼어요.','beautiful','A1','humanities',3,'beauty art landscape poem'),
('w_humanities_A1_23','short','/ʃɔːrt/','adjective','짧은','Small in length or time.','I prefer {short} stories to long novels.','저는 긴 소설보다 단편을 더 좋아해요.','short','A1','humanities',2,'short story brief pages'),
('w_humanities_A1_24','language','/ˈlæŋɡwɪdʒ/','noun','언어','A system of communication used by a group.','English is a global {language}.','영어는 세계 언어예요.','language','A1','humanities',1,'language communication speech text'),
('w_humanities_A1_25','draw','/drɔː/','verb','그리다','To make a picture with a pencil or pen.','She likes to {draw} characters from her favorite stories.','그녀는 좋아하는 이야기의 등장인물을 그리는 걸 좋아해요.','draw','A1','humanities',3,'drawing art sketch pencil'),
('w_humanities_A1_26','end','/end/','noun','끝, 결말','The final part of something.','The {end} of the story surprised everyone.','이야기의 결말이 모두를 놀라게 했어요.','end','A1','humanities',2,'ending story conclusion book'),
('w_humanities_A1_27','start','/stɑːrt/','verb','시작하다','To begin something.','Where does the story {start}?','이야기가 어디서 시작되나요?','start','A1','humanities',2,'beginning start open book'),
('w_humanities_A1_28','tell','/tel/','verb','말하다, 이야기하다','To communicate facts or a story in spoken or written words.','Can you {tell} me about your favorite book?','좋아하는 책에 대해 이야기해 줄 수 있어요?','tell','A1','humanities',1,'talking storytelling sharing'),
('w_humanities_A1_29','mean','/miːn/','verb','의미하다','To intend to convey; to signify.','What does this phrase {mean}?','이 구절은 무슨 뜻이에요?','mean','A1','humanities',1,'meaning definition understanding'),
('w_humanities_A1_30','listen','/ˈlɪsən/','verb','듣다','To pay attention to sounds.','I love to {listen} to audiobooks.','저는 오디오북 듣는 걸 좋아해요.','listen','A1','humanities',2,'listening audio headphones book'),
('w_humanities_A1_31','enjoy','/ɪnˈdʒɔɪ/','verb','즐기다','To take pleasure in something.','I {enjoy} reading classic literature.','저는 고전 문학 읽는 걸 즐겨요.','enjoy','A1','humanities',1,'enjoying reading leisure books'),
('w_humanities_A1_32','world','/wɜːrld/','noun','세계, 세상','The earth and all its people; a realm of existence.','Great literature opens up the {world}.','훌륭한 문학은 세계를 열어줘요.','world','A1','humanities',1,'world globe earth explore'),
('w_humanities_A1_33','real','/riːl/','adjective','진짜의, 현실의','Actually existing; not imagined.','The characters feel very {real}.','등장인물들이 매우 현실적으로 느껴져요.','real','A1','humanities',2,'reality authentic genuine truth'),
('w_humanities_A1_34','class','/klɑːs/','noun','수업; 계층','A group lesson; also a social division.','We discussed the poem in {class}.','수업에서 그 시에 대해 토론했어요.','class','A1','humanities',2,'classroom learning education discussion'),
('w_humanities_A1_35','remember','/rɪˈmembər/','verb','기억하다','To have in mind or bring back to mind.','I always {remember} the first book I loved.','저는 처음 좋아했던 책을 항상 기억해요.','remember','A1','humanities',2,'memory remember nostalgia books');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A2_01','author','/ˈɔːθər/','noun','작가','A person who writes books or articles.','My favorite {author} has written over twenty novels.','제가 가장 좋아하는 작가는 소설을 20편 넘게 썼어요.','author','A2','humanities',1,'writer author desk books'),
('w_humanities_A2_02','novel','/ˈnɒvəl/','noun','소설','A long fictional prose narrative.','I just finished reading a great {novel}.','방금 훌륭한 소설을 다 읽었어요.','novel','A2','humanities',1,'novel book fiction reading'),
('w_humanities_A2_03','character','/ˈkærɪktər/','noun','등장인물; 성격','A person in a story or play; a person''s nature.','The main {character} changes throughout the story.','주인공은 이야기 내내 변해가요.','character','A2','humanities',1,'character portrait story person'),
('w_humanities_A2_04','chapter','/ˈtʃæptər/','noun','챕터, 장','A main division of a book.','I read two {chapter}s before bed every night.','저는 매일 밤 자기 전에 챕터를 두 개 읽어요.','chapter','A2','humanities',2,'book chapter pages reading'),
('w_humanities_A2_05','culture','/ˈkʌltʃər/','noun','문화','The customs and values of a society.','Literature reflects the {culture} of its time.','문학은 시대의 문화를 반영해요.','culture','A2','humanities',1,'culture diversity society tradition'),
('w_humanities_A2_06','tradition','/trəˈdɪʃən/','noun','전통','A long-established custom passed down through generations.','Oral storytelling is an important {tradition}.','구전 이야기하기는 중요한 전통이에요.','tradition','A2','humanities',2,'tradition heritage culture folk'),
('w_humanities_A2_07','myth','/mɪθ/','noun','신화','A traditional story, especially one explaining a natural phenomenon.','The Greek {myth} of Icarus is still famous.','이카로스에 관한 그리스 신화는 아직도 유명해요.','myth','A2','humanities',2,'mythology ancient Greece story'),
('w_humanities_A2_08','legend','/ˈledʒənd/','noun','전설','A traditional story about a famous person or event.','King Arthur is a well-known English {legend}.','아서 왕은 유명한 영국 전설이에요.','legend','A2','humanities',2,'legend folklore hero ancient'),
('w_humanities_A2_09','hero','/ˈhɪərəʊ/','noun','영웅; 주인공','A person admired for courage; the main character.','Every great story has a {hero} who faces challenges.','모든 훌륭한 이야기에는 도전에 맞서는 영웅이 있어요.','hero','A2','humanities',1,'hero courage adventure story'),
('w_humanities_A2_10','describe','/dɪˈskraɪb/','verb','묘사하다','To give a detailed account of something.','The author uses vivid language to {describe} the setting.','작가는 생생한 언어로 배경을 묘사해요.','describe','A2','humanities',1,'description detail writing vivid'),
('w_humanities_A2_11','imagination','/ɪˌmædʒɪˈneɪʃən/','noun','상상력','The ability to form new ideas not present to the senses.','Reading develops your {imagination}.','독서는 상상력을 키워줘요.','imagination','A2','humanities',1,'imagination creativity dream art'),
('w_humanities_A2_12','poetry','/ˈpoʊɪtri/','noun','시(詩) 전반','Literary work in verse, expressing feelings and ideas.','She studied {poetry} at university.','그녀는 대학에서 시를 공부했어요.','poetry','A2','humanities',2,'poetry book verse literature'),
('w_humanities_A2_13','fiction','/ˈfɪkʃən/','noun','소설, 허구','Literature that describes imaginary events and people.','Science {fiction} often predicts the future.','공상과학 소설은 종종 미래를 예측해요.','fiction','A2','humanities',2,'fiction books library story'),
('w_humanities_A2_14','drama','/ˈdrɑːmə/','noun','희곡; 드라마','A play for theatre or TV; an exciting series of events.','Shakespeare''s {drama} is still performed worldwide.','셰익스피어의 희곡은 전 세계에서 아직도 공연돼요.','drama','A2','humanities',2,'theater drama stage performance'),
('w_humanities_A2_15','express','/ɪkˈspres/','verb','표현하다','To convey feelings or ideas through words or art.','Writers {express} their inner world through stories.','작가들은 이야기를 통해 내면 세계를 표현해요.','express','A2','humanities',1,'expression art writing feeling'),
('w_humanities_A2_16','meaning','/ˈmiːnɪŋ/','noun','의미','What is intended or expressed.','What is the deeper {meaning} of this poem?','이 시의 더 깊은 의미는 무엇인가요?','meaning','A2','humanities',1,'meaning depth significance text'),
('w_humanities_A2_17','publish','/ˈpʌblɪʃ/','verb','출판하다','To prepare and issue a book or article for public sale.','Her debut novel was {publish}ed last spring.','그녀의 데뷔 소설은 지난 봄에 출판됐어요.','publish','A2','humanities',2,'publishing book print release'),
('w_humanities_A2_18','audience','/ˈɔːdiəns/','noun','독자; 관객','The group of people who read or watch a work.','The author writes for a young adult {audience}.','작가는 청소년 독자를 위해 글을 써요.','audience','A2','humanities',2,'audience readers crowd people'),
('w_humanities_A2_19','setting','/ˈsetɪŋ/','noun','배경','The time and place in which a story is set.','The {setting} of the novel is 19th-century London.','소설의 배경은 19세기 런던이에요.','setting','A2','humanities',2,'setting landscape scene place'),
('w_humanities_A2_20','plot','/plɒt/','noun','줄거리','The sequence of events in a story.','The {plot} of the movie was very unexpected.','영화의 줄거리가 매우 예상 밖이었어요.','plot','A2','humanities',1,'plot story twist narrative'),
('w_humanities_A2_21','inspire','/ɪnˈspaɪər/','verb','영감을 주다','To stimulate creative feeling or thought.','Great literature can {inspire} people to change.','훌륭한 문학은 사람들이 변화하도록 영감을 줄 수 있어요.','inspire','A2','humanities',1,'inspiration creativity idea art'),
('w_humanities_A2_22','compare','/kəmˈpeər/','verb','비교하다','To note the similarities and differences between two things.','Let''s {compare} these two short stories.','이 두 단편 소설을 비교해 봐요.','compare','A2','humanities',2,'comparison contrast analysis side'),
('w_humanities_A2_23','message','/ˈmesɪdʒ/','noun','메시지, 주제','The central idea or lesson of a work.','What {message} is the author trying to send?','작가가 전달하려는 메시지는 무엇인가요?','message','A2','humanities',2,'message meaning theme writing'),
('w_humanities_A2_24','century','/ˈsentʃəri/','noun','세기, 100년','A period of one hundred years.','This novel was written in the 19th {century}.','이 소설은 19세기에 쓰였어요.','century','A2','humanities',2,'century history timeline era'),
('w_humanities_A2_25','popular','/ˈpɒpjʊlər/','adjective','인기 있는','Liked or admired by many people.','This novel is very {popular} among teenagers.','이 소설은 십대들 사이에서 매우 인기 있어요.','popular','A2','humanities',2,'popular bestseller book trend'),
('w_humanities_A2_26','original','/əˈrɪdʒɪnəl/','adjective','독창적인; 원본의','New and creative; the first version of something.','The {original} manuscript is kept in a museum.','원본 원고는 박물관에 보관돼 있어요.','original','A2','humanities',2,'original authentic first edition'),
('w_humanities_A2_27','translate','/trænsˈleɪt/','verb','번역하다','To convert text from one language to another.','This novel has been {translate}d into 30 languages.','이 소설은 30개 언어로 번역됐어요.','translate','A2','humanities',2,'translation language global book'),
('w_humanities_A2_28','scene','/siːn/','noun','장면','A part of a play or story depicting a single event.','My favorite {scene} is at the end of chapter three.','제가 가장 좋아하는 장면은 3장 끝 부분이에요.','scene','A2','humanities',2,'scene movie play moment'),
('w_humanities_A2_29','creative','/kriˈeɪtɪv/','adjective','창의적인','Having the ability to produce new and imaginative ideas.','Writing requires a very {creative} mind.','글쓰기는 매우 창의적인 사고를 필요로 해요.','creative','A2','humanities',1,'creative imagination art design'),
('w_humanities_A2_30','opinion','/əˈpɪnjən/','noun','의견','A personal view or judgement.','In your {opinion}, what is the best novel ever written?','당신 의견으로는 역대 최고의 소설이 무엇이에요?','opinion','A2','humanities',1,'opinion view perspective discuss'),
('w_humanities_A2_31','award','/əˈwɔːrd/','noun','상, 수상','A prize given for achievement.','The novel won a major literary {award}.','그 소설은 주요 문학상을 받았어요.','award','A2','humanities',2,'award prize trophy achievement'),
('w_humanities_A2_32','ancient','/ˈeɪnʃənt/','adjective','고대의','Belonging to the very distant past.','{Ancient} myths still influence modern storytelling.','고대 신화는 아직도 현대 이야기 방식에 영향을 미쳐요.','ancient','A2','humanities',2,'ancient history ruins civilization'),
('w_humanities_A2_33','folktale','/ˈfoʊkteɪl/','noun','민담, 민화','A story passed down through ordinary people.','Korean {folktale}s often teach moral lessons.','한국 민담은 종종 도덕적 교훈을 가르쳐요.','folktale','A2','humanities',2,'folktale tradition culture story'),
('w_humanities_A2_34','narrative','/ˈnærətɪv/','noun','서사, 이야기 방식','A spoken or written account of events.','The {narrative} switches between two characters.','서사는 두 인물 사이를 오가요.','narrative','A2','humanities',1,'narrative storytelling structure plot'),
('w_humanities_A2_35','genre','/ˈʒɑːnrə/','noun','장르','A category of artistic work defined by style or subject.','What is your favorite literary {genre}?','가장 좋아하는 문학 장르가 뭐예요?','genre','A2','humanities',1,'genre category books shelf');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B1_01','metaphor','/ˈmetəfɔːr/','noun','은유','A figure of speech applying a word or phrase to something it does not literally denote.','The author uses a powerful {metaphor} to describe grief.','작가는 슬픔을 묘사하기 위해 강력한 은유를 사용해요.','metaphor','B1','humanities',1,'metaphor language poetry figure'),
('w_humanities_B1_02','theme','/θiːm/','noun','주제, 테마','The central subject or idea explored in a work.','The main {theme} of the novel is redemption.','소설의 주된 주제는 구원이에요.','theme','B1','humanities',1,'theme idea central message'),
('w_humanities_B1_03','symbolism','/ˈsɪmbəlɪzəm/','noun','상징주의; 상징성','The use of symbols to represent ideas or qualities.','The green light in Gatsby is famous for its {symbolism}.','개츠비의 초록불은 상징성으로 유명해요.','symbolism','B1','humanities',1,'symbol meaning literature art'),
('w_humanities_B1_04','analyze','/ˈænəlaɪz/','verb','분석하다','To examine in detail to understand or explain.','Students are asked to {analyze} the poem''s structure.','학생들은 시의 구조를 분석하도록 요청받아요.','analyze','B1','humanities',1,'analysis research study detail'),
('w_humanities_B1_05','interpret','/ɪnˈtɜːrprɪt/','verb','해석하다','To explain the meaning of something.','How do you {interpret} the final scene?','마지막 장면을 어떻게 해석하세요?','interpret','B1','humanities',1,'interpretation meaning analysis view'),
('w_humanities_B1_06','literary','/ˈlɪtərəri/','adjective','문학적인','Relating to the writing or study of literature.','She has a deep appreciation for {literary} fiction.','그녀는 문학 소설을 깊이 좋아해요.','literary','B1','humanities',1,'literary books writing academic'),
('w_humanities_B1_07','classic','/ˈklæsɪk/','adjective / noun','고전적인; 고전 작품','Of recognized and enduring quality; a great work of art.','Romeo and Juliet is a {classic} of English literature.','로미오와 줄리엣은 영문학의 고전이에요.','classic','B1','humanities',1,'classic literature timeless book'),
('w_humanities_B1_08','critique','/krɪˈtiːk/','noun','비평','A detailed analysis and assessment of a work.','He wrote a {critique} of the novel for the magazine.','그는 잡지에 소설 비평을 썼어요.','critique','B1','humanities',2,'critique review analysis writing'),
('w_humanities_B1_09','perspective','/pərˈspektɪv/','noun','관점','A particular way of viewing something.','Read the story from the narrator''s {perspective}.','화자의 관점에서 이야기를 읽어보세요.','perspective','B1','humanities',1,'perspective viewpoint angle idea'),
('w_humanities_B1_10','contrast','/ˈkɒntræst/','noun','대비, 대조','The state of being strikingly different from something else.','The author uses sharp {contrast} to highlight injustice.','작가는 불의를 강조하기 위해 날카로운 대비를 사용해요.','contrast','B1','humanities',2,'contrast comparison black white'),
('w_humanities_B1_11','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of and relations between the parts of a text.','The {structure} of this poem is unusual.','이 시의 구조는 독특해요.','structure','B1','humanities',2,'structure architecture design order'),
('w_humanities_B1_12','conflict','/ˈkɒnflɪkt/','noun','갈등','A serious disagreement; the central struggle in a narrative.','The internal {conflict} of the protagonist drives the story.','주인공의 내적 갈등이 이야기를 이끌어요.','conflict','B1','humanities',1,'conflict tension struggle drama'),
('w_humanities_B1_13','narrator','/nəˈreɪtər/','noun','화자, 서술자','The person who tells a story.','The {narrator} is unreliable, which creates suspense.','화자가 신뢰할 수 없어서 긴장감이 생겨요.','narrator','B1','humanities',2,'narrator voice storytelling book'),
('w_humanities_B1_14','tone','/toʊn/','noun','어조, 분위기','The general attitude of a writer toward the subject.','The {tone} of the poem shifts from joy to sadness.','시의 어조가 기쁨에서 슬픔으로 바뀌어요.','tone','B1','humanities',2,'tone mood atmosphere writing'),
('w_humanities_B1_15','imagery','/ˈɪmɪdʒəri/','noun','심상, 이미지','Visually descriptive or figurative language.','Rich {imagery} makes the poem come alive.','풍부한 심상이 시를 생동감 있게 만들어요.','imagery','B1','humanities',2,'imagery visualization poetry vivid'),
('w_humanities_B1_16','influence','/ˈɪnflʊəns/','noun','영향','The power to affect others.','Hemingway had a great {influence} on modern prose.','헤밍웨이는 현대 산문에 큰 영향을 미쳤어요.','influence','B1','humanities',1,'influence impact effect inspiration'),
('w_humanities_B1_17','context','/ˈkɒntekst/','noun','맥락, 문맥','The circumstances in which something exists or occurs.','Understanding the historical {context} helps us read the text better.','역사적 맥락을 이해하면 텍스트를 더 잘 읽을 수 있어요.','context','B1','humanities',1,'context background history text'),
('w_humanities_B1_18','symbol','/ˈsɪmbəl/','noun','상징','A thing representing or standing for something else.','The dove is a {symbol} of peace in many cultures.','비둘기는 많은 문화에서 평화의 상징이에요.','symbol','B1','humanities',1,'symbol peace dove meaning'),
('w_humanities_B1_19','biography','/baɪˈɒɡrəfi/','noun','전기(傳記)','An account of a person''s life written by someone else.','I read a {biography} of Shakespeare last year.','작년에 셰익스피어 전기를 읽었어요.','biography','B1','humanities',2,'biography life story portrait'),
('w_humanities_B1_20','tradition','/trəˈdɪʃən/','noun','문학 전통','A long-established custom or practice passed across generations.','Greek tragedy is central to the Western literary {tradition}.','그리스 비극은 서양 문학 전통의 핵심이에요.','tradition','B1','humanities',2,'tradition heritage classic western'),
('w_humanities_B1_21','tragedy','/ˈtrædʒɪdi/','noun','비극','A serious play or event with an unhappy ending.','Hamlet is one of Shakespeare''s greatest {tragedy} plays.','햄릿은 셰익스피어의 가장 위대한 비극 중 하나예요.','tragedy','B1','humanities',2,'tragedy drama sad ending stage'),
('w_humanities_B1_22','comedy','/ˈkɒmɪdi/','noun','희극','A play or story intended to be funny with a happy ending.','A Midsummer Night''s Dream is a celebrated {comedy}.','한여름 밤의 꿈은 유명한 희극이에요.','comedy','B1','humanities',3,'comedy humor play happy'),
('w_humanities_B1_23','verse','/vɜːrs/','noun','운문, 절','Writing arranged in lines with a rhythm; a stanza.','The poem is written in four-line {verse}s.','그 시는 4행 절로 쓰여 있어요.','verse','B1','humanities',2,'verse poetry rhyme stanza'),
('w_humanities_B1_24','prose','/proʊz/','noun','산문','Written or spoken language in its ordinary form.','The novel is written in beautiful, flowing {prose}.','소설은 아름답고 유려한 산문으로 쓰여 있어요.','prose','B1','humanities',2,'prose writing paragraphs style'),
('w_humanities_B1_25','reference','/ˈrefərəns/','noun','참조, 언급','A mention of or citation from another work.','The novel contains many {reference}s to Greek mythology.','소설에는 그리스 신화에 대한 언급이 많아요.','reference','B1','humanities',2,'reference citation source text'),
('w_humanities_B1_26','quotation','/kwoʊˈteɪʃən/','noun','인용문','A group of words repeated from a text.','She opened her essay with a {quotation} from Austen.','그녀는 오스틴의 인용문으로 에세이를 시작했어요.','quotation','B1','humanities',2,'quote citation text highlight'),
('w_humanities_B1_27','essay','/ˈeseɪ/','noun','에세이, 수필','A short piece of writing on a particular subject.','He wrote an {essay} comparing two famous novels.','그는 두 유명한 소설을 비교하는 에세이를 썼어요.','essay','B1','humanities',2,'essay writing analysis paper'),
('w_humanities_B1_28','respond','/rɪˈspɒnd/','verb','반응하다, 응하다','To say or write something in reply; to react.','How did readers {respond} to the new novel?','독자들은 새 소설에 어떻게 반응했나요?','respond','B1','humanities',2,'response reaction reader feedback'),
('w_humanities_B1_29','explore','/ɪkˈsplɔːr/','verb','탐구하다','To examine thoroughly; to investigate ideas.','The novel {explore}s themes of identity and belonging.','소설은 정체성과 귀속감의 주제를 탐구해요.','explore','B1','humanities',1,'explore discovery research idea'),
('w_humanities_B1_30','cultural','/ˈkʌltʃərəl/','adjective','문화적인','Relating to the culture of a society.','The novel has great {cultural} significance.','그 소설은 문화적으로 큰 의미를 지녀요.','cultural','B1','humanities',1,'cultural heritage society art'),
('w_humanities_B1_31','reveal','/rɪˈviːl/','verb','드러내다, 밝히다','To make known something previously hidden or unknown.','The final chapter {reveal}s the true identity of the killer.','마지막 챕터에서 살인자의 진짜 정체가 드러나요.','reveal','B1','humanities',2,'reveal surprise discovery truth'),
('w_humanities_B1_32','audience','/ˈɔːdiəns/','noun','독자, 청중','The intended readers or viewers of a work.','The book found a wide {audience} in Europe.','그 책은 유럽에서 넓은 독자층을 형성했어요.','audience','B1','humanities',2,'audience readers crowd reception'),
('w_humanities_B1_33','passage','/ˈpæsɪdʒ/','noun','구절, 단락','A short section taken from a longer text.','This {passage} from the novel is often quoted.','소설의 이 구절은 자주 인용돼요.','passage','B1','humanities',2,'passage text excerpt highlight'),
('w_humanities_B1_34','illustrate','/ˈɪləstreɪt/','verb','설명하다; 삽화를 넣다','To explain or make clear with examples or pictures.','The author uses anecdotes to {illustrate} the theme.','작가는 주제를 설명하기 위해 일화를 사용해요.','illustrate','B1','humanities',2,'illustration example visual explain'),
('w_humanities_B1_35','impact','/ˈɪmpækt/','noun','영향, 충격','A strong effect or impression.','This book had a huge {impact} on my life.','이 책은 제 삶에 큰 영향을 미쳤어요.','impact','B1','humanities',1,'impact effect change influence');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B2_01','allegory','/ˈæləɡɔːri/','noun','알레고리, 풍유','A narrative with a hidden symbolic meaning.','Animal Farm is a well-known political {allegory}.','동물농장은 유명한 정치적 알레고리예요.','allegory','B2','humanities',1,'allegory symbol story meaning'),
('w_humanities_B2_02','archetype','/ˈɑːrkɪtaɪp/','noun','원형, 아키타입','A very typical example of a character or situation.','The wise old mentor is a classic literary {archetype}.','현명한 노인 멘토는 고전적인 문학 원형이에요.','archetype','B2','humanities',1,'archetype hero mentor pattern'),
('w_humanities_B2_03','motif','/moʊˈtiːf/','noun','모티프, 반복 요소','A recurring image, idea, or symbol in a work.','The {motif} of water runs throughout the novel.','물의 모티프가 소설 전체에 흐르고 있어요.','motif','B2','humanities',1,'motif pattern symbol repeat'),
('w_humanities_B2_04','subtext','/ˈsʌbtekst/','noun','숨겨진 의미, 서브텍스트','An underlying theme in a work that is not explicitly stated.','The {subtext} of the dialogue reveals jealousy.','대화의 숨겨진 의미는 질투를 드러내요.','subtext','B2','humanities',2,'subtext hidden meaning reading'),
('w_humanities_B2_05','irony','/ˈaɪrəni/','noun','아이러니, 반어','The expression of meaning through language that signifies the opposite.','The title of the novel is full of {irony}.','소설의 제목은 아이러니로 가득해요.','irony','B2','humanities',1,'irony contrast meaning twist'),
('w_humanities_B2_06','paradox','/ˈpærədɒks/','noun','역설','A seemingly contradictory statement that may be true.','The poet expresses grief through the {paradox} of joyful language.','시인은 기쁜 언어의 역설을 통해 슬픔을 표현해요.','paradox','B2','humanities',1,'paradox contradiction truth meaning'),
('w_humanities_B2_07','satire','/ˈsætaɪər/','noun','풍자','The use of humor or irony to criticize society.','Swift''s Gulliver''s Travels is a masterpiece of {satire}.','스위프트의 걸리버 여행기는 풍자의 걸작이에요.','satire','B2','humanities',1,'satire criticism humor society'),
('w_humanities_B2_08','bildungsroman','/ˈbɪldʊŋzroʊˌmɑːn/','noun','성장 소설','A novel about a young person''s moral and psychological growth.','The Catcher in the Rye is a famous {bildungsroman}.','호밀밭의 파수꾼은 유명한 성장 소설이에요.','bildungsroman','B2','humanities',2,'coming of age youth growth story'),
('w_humanities_B2_09','modernism','/ˈmɒdərnɪzəm/','noun','모더니즘','A movement in literature and arts rejecting traditional forms.','Virginia Woolf is a key figure of literary {modernism}.','버지니아 울프는 문학 모더니즘의 핵심 인물이에요.','modernism','B2','humanities',2,'modernism art movement twentieth century'),
('w_humanities_B2_10','existentialism','/ˌeɡzɪˈstenʃəlɪzəm/','noun','실존주의','A philosophical theory that humans define their own meaning.','Camus'' work is deeply rooted in {existentialism}.','카뮈의 작품은 실존주의에 깊이 뿌리를 두고 있어요.','existentialism','B2','humanities',2,'existentialism philosophy meaning freedom'),
('w_humanities_B2_11','allusion','/əˈluːʒən/','noun','암시, 전고(典故)','An indirect reference to a person, event, or work.','The poem contains an {allusion} to the Bible.','시에는 성경에 대한 암시가 담겨 있어요.','allusion','B2','humanities',2,'allusion reference history intertextual'),
('w_humanities_B2_12','ambiguity','/ˌæmbɪˈɡjuːɪti/','noun','모호함, 중의성','The quality of being open to more than one interpretation.','The ending is left in deliberate {ambiguity}.','결말은 의도적인 모호함으로 남겨져 있어요.','ambiguity','B2','humanities',2,'ambiguity meaning uncertain open'),
('w_humanities_B2_13','foreshadowing','/fɔːrˈʃædoʊɪŋ/','noun','복선','A literary technique used to hint at future events.','The ominous weather is a form of {foreshadowing}.','불길한 날씨는 복선의 일종이에요.','foreshadowing','B2','humanities',2,'foreshadowing hint clue future'),
('w_humanities_B2_14','postmodernism','/ˌpoʊstˈmɒdərnɪzəm/','noun','포스트모더니즘','A movement rejecting modernism''s grand narratives.','{Postmodernism} often questions the nature of truth in fiction.','포스트모더니즘은 종종 소설에서 진실의 본질에 의문을 제기해요.','postmodernism','B2','humanities',2,'postmodern art culture contemporary'),
('w_humanities_B2_15','unreliable','/ˌʌnrɪˈlaɪəbəl/','adjective','믿을 수 없는','Not able to be trusted or depended on.','The {unreliable} narrator keeps the reader guessing.','믿을 수 없는 화자는 독자를 계속 추측하게 만들어요.','unreliable','B2','humanities',2,'unreliable narrator deception twist'),
('w_humanities_B2_16','catharsis','/kəˈθɑːrsɪs/','noun','카타르시스, 정화','The process of releasing strong emotions through art.','Greek tragedy aimed to produce {catharsis} in the audience.','그리스 비극은 관객에게 카타르시스를 일으키는 것을 목표로 했어요.','catharsis','B2','humanities',2,'catharsis emotion release theater'),
('w_humanities_B2_17','aesthetic','/esˈθetɪk/','adjective / noun','미적인; 미학','Concerned with beauty or the appreciation of beauty.','The novel has a strong {aesthetic} sensibility.','소설은 강한 미적 감수성을 지녀요.','aesthetic','B2','humanities',2,'aesthetic beauty art design'),
('w_humanities_B2_18','epic','/ˈepɪk/','noun / adjective','서사시; 장대한','A long poem narrating heroic deeds; impressively large in scale.','The Iliad is an ancient Greek {epic}.','일리아드는 고대 그리스 서사시예요.','epic','B2','humanities',2,'epic poem hero ancient journey'),
('w_humanities_B2_19','dialect','/ˈdaɪəlekt/','noun','방언, 사투리','A form of language spoken by a particular group.','The novel uses regional {dialect} to create authenticity.','소설은 진정성을 만들기 위해 지역 방언을 사용해요.','dialect','B2','humanities',3,'dialect language regional speech'),
('w_humanities_B2_20','characterization','/ˌkærɪktərɪˈzeɪʃən/','noun','인물 묘사','The way an author develops the personalities of characters.','The {characterization} in this novel is remarkably subtle.','이 소설의 인물 묘사는 놀라울 정도로 섬세해요.','characterization','B2','humanities',2,'character development portrayal depth'),
('w_humanities_B2_21','juxtaposition','/ˌdʒʌkstəpəˈzɪʃən/','noun','병치, 대비 배치','Placing two things close together for contrasting effect.','The author uses {juxtaposition} to show social inequality.','작가는 사회적 불평등을 보여주기 위해 병치를 사용해요.','juxtaposition','B2','humanities',2,'juxtaposition contrast side by side'),
('w_humanities_B2_22','omniscient','/ɒmˈnɪʃənt/','adjective','전지적인','Having unlimited knowledge; used of a narrative perspective.','The story is told from an {omniscient} point of view.','이야기는 전지적 관점에서 서술돼요.','omniscient','B2','humanities',2,'omniscient narrator perspective view'),
('w_humanities_B2_23','realism','/ˈriːəlɪzəm/','noun','리얼리즘, 사실주의','A movement depicting subjects as they actually are.','19th-century {realism} aimed to portray everyday life accurately.','19세기 사실주의는 일상을 정확하게 묘사하는 것을 목표로 했어요.','realism','B2','humanities',2,'realism art everyday authentic'),
('w_humanities_B2_24','romanticism','/roʊˈmæntɪsɪzəm/','noun','낭만주의','An artistic movement emphasizing emotion and nature.','Keats is one of the most celebrated poets of {romanticism}.','키츠는 낭만주의에서 가장 유명한 시인 중 한 명이에요.','romanticism','B2','humanities',2,'romanticism nature emotion poetry'),
('w_humanities_B2_25','canon','/ˈkænən/','noun','정전(正典), 문학 캐논','The works generally accepted as the greatest in a given field.','The Western literary {canon} has been criticized for its lack of diversity.','서양 문학 캐논은 다양성 부족으로 비판받아왔어요.','canon','B2','humanities',2,'canon classic literature list'),
('w_humanities_B2_26','rhetoric','/ˈretərɪk/','noun','수사학; 수사법','The art of effective or persuasive speaking or writing.','Political speeches rely heavily on {rhetoric}.','정치 연설은 수사법에 크게 의존해요.','rhetoric','B2','humanities',2,'rhetoric persuasion speech language'),
('w_humanities_B2_27','infer','/ɪnˈfɜːr/','verb','추론하다','To deduce from evidence rather than explicit statement.','We can {infer} the character''s true feelings from his actions.','그의 행동으로부터 그 인물의 진짜 감정을 추론할 수 있어요.','infer','B2','humanities',2,'inference deduction reading between lines'),
('w_humanities_B2_28','trauma','/ˈtrɔːmə/','noun','트라우마','A deeply distressing experience; its lasting psychological effect.','The author explores childhood {trauma} through the protagonist.','작가는 주인공을 통해 어린 시절 트라우마를 탐구해요.','trauma','B2','humanities',2,'trauma psychology emotion healing'),
('w_humanities_B2_29','dystopia','/dɪˈstoʊpiə/','noun','디스토피아','An imagined world where everything is unpleasant or unjust.','1984 is a classic {dystopia} novel.','1984는 고전적인 디스토피아 소설이에요.','dystopia','B2','humanities',2,'dystopia dark future society'),
('w_humanities_B2_30','utopia','/juːˈtoʊpiə/','noun','유토피아','An imagined perfect society.','Thomas More coined the term {utopia} in 1516.','토마스 모어는 1516년에 유토피아라는 용어를 만들었어요.','utopia','B2','humanities',2,'utopia ideal perfect society'),
('w_humanities_B2_31','morality','/məˈrælɪti/','noun','도덕성','Principles concerning the distinction between right and wrong.','Victorian novels often focused on questions of {morality}.','빅토리아 시대 소설은 종종 도덕성 문제에 집중했어요.','morality','B2','humanities',2,'morality ethics right wrong'),
('w_humanities_B2_32','ambivalence','/æmˈbɪvələns/','noun','양가감정, 양의성','Mixed feelings about someone or something.','The hero''s {ambivalence} toward his father drives the plot.','아버지에 대한 영웅의 양가감정이 줄거리를 이끌어요.','ambivalence','B2','humanities',3,'ambivalence mixed feelings conflict'),
('w_humanities_B2_33','consciousness','/ˈkɒnʃəsnəs/','noun','의식(意識)','The state of being aware; the stream of thoughts.','Virginia Woolf pioneered stream-of-{consciousness} narration.','버지니아 울프는 의식의 흐름 서술 방식을 개척했어요.','consciousness','B2','humanities',2,'consciousness mind stream thought'),
('w_humanities_B2_34','absurd','/əbˈsɜːrd/','adjective','부조리한, 불합리한','Wildly unreasonable or inappropriate; contrary to logic.','Kafka''s work captures the {absurd} nature of modern bureaucracy.','카프카의 작품은 현대 관료주의의 부조리한 특성을 담아요.','absurd','B2','humanities',2,'absurd surreal illogical kafkaesque'),
('w_humanities_B2_35','critique','/krɪˈtiːk/','verb','비평하다','To evaluate a work in detail.','She was asked to {critique} a postmodern short story.','그녀는 포스트모던 단편 소설을 비평해달라는 요청을 받았어요.','critique','B2','humanities',2,'critique analysis evaluation writing');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C1_01','hermeneutics','/ˌhɜːrmɪˈnjuːtɪks/','noun','해석학','The theory and methodology of interpretation, especially of texts.','Biblical {hermeneutics} has shaped centuries of scholarship.','성경 해석학은 수 세기의 학문을 형성해왔어요.','hermeneutics','C1','humanities',2,'hermeneutics interpretation text philosophy'),
('w_humanities_C1_02','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','{Semiotics} helps us decode the hidden meaning of images.','기호학은 이미지의 숨겨진 의미를 해독하는 데 도움이 돼요.','semiotics','C1','humanities',2,'semiotics signs symbols meaning'),
('w_humanities_C1_03','intertextuality','/ˌɪntərtekstʃuˈælɪti/','noun','상호텍스트성','The relationship between texts, especially through allusion or quotation.','The novel''s {intertextuality} with Homer enriches its meaning.','호머와의 상호텍스트성이 소설의 의미를 풍부하게 해요.','intertextuality','C1','humanities',1,'intertextuality reference allusion text'),
('w_humanities_C1_04','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의','A method of analysis that challenges fixed meanings in texts.','Derrida''s {deconstruction} revolutionized literary criticism.','데리다의 해체주의는 문학 비평을 혁신했어요.','deconstruction','C1','humanities',2,'deconstruction theory text meaning'),
('w_humanities_C1_05','poststructuralism','/ˌpoʊstˈstrʌktʃərəlɪzəm/','noun','포스트구조주의','A theory challenging the stable meanings proposed by structuralism.','{Poststructuralism} questions whether texts have fixed meanings.','포스트구조주의는 텍스트에 고정된 의미가 있는지 의문을 제기해요.','poststructuralism','C1','humanities',2,'poststructuralism theory language text'),
('w_humanities_C1_06','phenomenology','/fɪˌnɒmɪˈnɒlədʒi/','noun','현상학','The philosophical study of structures of experience and consciousness.','Husserl''s {phenomenology} influenced literary theory deeply.','후설의 현상학은 문학 이론에 깊은 영향을 미쳤어요.','phenomenology','C1','humanities',2,'phenomenology experience consciousness philosophy'),
('w_humanities_C1_07','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of argument through contradictory ideas to arrive at truth.','Hegel''s {dialectic} of thesis and antithesis shapes critical thought.','헤겔의 변증법은 비판적 사고를 형성해요.','dialectic','C1','humanities',2,'dialectic philosophy argument truth'),
('w_humanities_C1_08','mimesis','/mɪˈmiːsɪs/','noun','미메시스, 모방','The imitation or representation of the real world in art.','Aristotle''s concept of {mimesis} remains foundational to literary theory.','아리스토텔레스의 미메시스 개념은 문학 이론의 기초로 남아 있어요.','mimesis','C1','humanities',2,'mimesis imitation reality representation'),
('w_humanities_C1_09','sublime','/səˈblaɪm/','noun / adjective','숭고함; 숭고한','An aesthetic quality of greatness beyond beauty.','Burke''s essay on the {sublime} influenced Romantic poets.','버크의 숭고함에 관한 에세이는 낭만파 시인들에게 영향을 미쳤어요.','sublime','C1','humanities',2,'sublime beauty awe nature grandeur'),
('w_humanities_C1_10','aporia','/əˈpɔːriə/','noun','아포리아, 논리적 난제','A state of irresolvable doubt or contradiction in a text.','Deconstructive readings often expose the {aporia} in classic texts.','해체주의적 독해는 종종 고전 텍스트의 아포리아를 드러내요.','aporia','C1','humanities',3,'aporia paradox contradiction philosophy'),
('w_humanities_C1_11','hegemony','/hɪˈdʒemənɪ/','noun','헤게모니, 패권','Dominance of one social group or nation over others.','Gramsci''s concept of cultural {hegemony} is central to critical theory.','그람시의 문화적 헤게모니 개념은 비판 이론의 핵심이에요.','hegemony','C1','humanities',2,'hegemony power culture society'),
('w_humanities_C1_12','ideology','/ˌaɪdiˈɒlədʒi/','noun','이데올로기','A system of ideas and ideals forming the basis of a theory.','Literary texts both reflect and reinforce dominant {ideology}.','문학 텍스트는 지배적 이데올로기를 반영하고 강화해요.','ideology','C1','humanities',2,'ideology belief system politics'),
('w_humanities_C1_13','discourse','/ˈdɪskɔːrs/','noun','담론, 담화','A mode of thinking or talking about a topic in a social context.','Foucault analyzed the {discourse} of power in society.','푸코는 사회에서 권력의 담론을 분석했어요.','discourse','C1','humanities',2,'discourse language power society'),
('w_humanities_C1_14','polyphony','/pəˈlɪfəni/','noun','다성(多聲), 폴리포니','A narrative technique using multiple voices or perspectives.','Bakhtin celebrated the {polyphony} of Dostoevsky''s novels.','바흐친은 도스토옙스키 소설의 다성성을 찬양했어요.','polyphony','C1','humanities',2,'polyphony voices narrative multiple'),
('w_humanities_C1_15','metafiction','/ˈmetəˌfɪkʃən/','noun','메타픽션','Fiction that self-consciously refers to its own fictional nature.','{Metafiction} blurs the boundary between story and reality.','메타픽션은 이야기와 현실의 경계를 흐려요.','metafiction','C1','humanities',2,'metafiction self-referential story reality'),
('w_humanities_C1_16','subaltern','/ˈsʌbəltɜːrn/','noun','서발턴 (하위 주체)','A marginalized social group excluded from dominant discourse.','Spivak asked whether the {subaltern} can speak.','스피박은 서발턴이 말할 수 있는지 물었어요.','subaltern','C1','humanities',3,'subaltern marginalized voice power'),
('w_humanities_C1_17','canon','/ˈkænən/','noun','문학 정전, 캐논','The body of books regarded as authoritative in a literary tradition.','Expanding the literary {canon} has been a key feminist goal.','문학 정전을 확장하는 것은 주요 페미니즘 목표였어요.','canon','C1','humanities',2,'canon classic literature tradition'),
('w_humanities_C1_18','structuralism','/ˈstrʌktʃərəlɪzəm/','noun','구조주의','An approach analyzing elements in relation to the broader system.','Saussure''s linguistics laid the foundation for {structuralism}.','소쉬르의 언어학은 구조주의의 기초를 놓았어요.','structuralism','C1','humanities',2,'structuralism theory language system'),
('w_humanities_C1_19','ambiguity','/ˌæmbɪˈɡjuːɪti/','noun','다의성, 모호성 (비평 용어)','The quality of being open to multiple interpretations in a literary text.','Empson identified seven types of {ambiguity} in poetry.','엠프슨은 시에서 일곱 가지 유형의 모호성을 발견했어요.','ambiguity','C1','humanities',2,'ambiguity interpretation meaning layers'),
('w_humanities_C1_20','trope','/troʊp/','noun','트로프, 수사적 형상','A figurative use of language; a recurring theme or device.','The "rags to riches" story is a well-worn literary {trope}.','신데렐라 스토리는 잘 알려진 문학적 트로프예요.','trope','C1','humanities',2,'trope figure rhetoric theme'),
('w_humanities_C1_21','episteme','/ˈepɪstiːm/','noun','에피스테메, 지식 체계','The set of ideas that defines knowledge in a given era (Foucault).','Foucault''s concept of {episteme} maps the limits of knowable thought.','푸코의 에피스테메 개념은 알 수 있는 사고의 한계를 그려요.','episteme','C1','humanities',3,'episteme knowledge era foucault'),
('w_humanities_C1_22','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','헤테로글로시아, 다언어성','The presence of multiple languages or voices in a text (Bakhtin).','Bakhtin valued {heteroglossia} as a sign of literary vitality.','바흐친은 헤테로글로시아를 문학적 활력의 징표로 여겼어요.','heteroglossia','C1','humanities',3,'heteroglossia voices language bakhtin'),
('w_humanities_C1_23','logocentrism','/ˈloʊɡoʊˌsentrɪzəm/','noun','로고스 중심주의','The assumption that language can fully represent thought (Derrida).','Derrida critiqued {logocentrism} as the foundation of Western metaphysics.','데리다는 로고스 중심주의를 서양 형이상학의 기초로 비판했어요.','logocentrism','C1','humanities',3,'logocentrism language meaning derrida'),
('w_humanities_C1_24','ontology','/ɒnˈtɒlədʒi/','noun','존재론','The branch of philosophy concerned with the nature of being.','The novel raises deep {ontology} questions about identity.','소설은 정체성에 대한 깊은 존재론적 질문을 제기해요.','ontology','C1','humanities',3,'ontology existence being philosophy'),
('w_humanities_C1_25','intertextual','/ˌɪntərˈtekstʃuəl/','adjective','상호텍스트적인','Relating to or involving connections between texts.','The poem is rich in {intertextual} references to the Bible.','이 시는 성경에 대한 상호텍스트적 언급이 풍부해요.','intertextual','C1','humanities',2,'intertextual reference allusion network'),
('w_humanities_C1_26','ecocriticism','/ˌiːkoʊˈkrɪtɪsɪzəm/','noun','생태비평','The study of literature in relation to the natural environment.','{Ecocriticism} examines how nature is represented in fiction.','생태비평은 소설에서 자연이 어떻게 표현되는지 살펴요.','ecocriticism','C1','humanities',3,'ecocriticism nature environment literature'),
('w_humanities_C1_27','postcolonialism','/ˌpoʊstˈkɒlənɪəlɪzəm/','noun','포스트식민주의','A field examining the cultural legacy of colonialism.','Chinua Achebe''s work is a cornerstone of {postcolonialism} studies.','치누아 아체베의 작품은 포스트식민주의 연구의 초석이에요.','postcolonialism','C1','humanities',2,'postcolonialism colonialism identity power'),
('w_humanities_C1_28','queer','/kwɪər/','adjective (literary theory)','퀴어 (이론 용어)','Relating to the examination of non-normative sexuality in literature.','A {queer} reading reveals the subtext of the Victorian novel.','퀴어 독해는 빅토리아 소설의 서브텍스트를 드러내요.','queer','C1','humanities',3,'queer theory identity literature subtext'),
('w_humanities_C1_29','narratology','/ˌnærəˈtɒlədʒi/','noun','서사학','The study of narrative structure and how it functions.','{Narratology} analyzes how stories are organized and told.','서사학은 이야기가 어떻게 구성되고 전달되는지 분석해요.','narratology','C1','humanities',2,'narratology structure story theory'),
('w_humanities_C1_30','lyric','/ˈlɪrɪk/','noun / adjective','서정시; 서정적인','A short poem expressing the writer''s emotions; intensely personal.','Keats is admired for his rich {lyric} poetry.','키츠는 풍부한 서정시로 존경받아요.','lyric','C1','humanities',2,'lyric poetry emotion personal'),
('w_humanities_C1_31','pathos','/ˈpeɪθɒs/','noun','파토스, 연민감','A quality in a work evoking pity or sadness.','The final scene is full of {pathos}.','마지막 장면은 파토스로 가득해요.','pathos','C1','humanities',2,'pathos emotion pity tragedy'),
('w_humanities_C1_32','lacuna','/ləˈkjuːnə/','noun','공백, 빠진 부분','A gap or missing portion in a text or argument.','The {lacuna} in the manuscript has puzzled scholars for decades.','원고의 공백은 수십 년간 학자들을 혼란스럽게 했어요.','lacuna','C1','humanities',3,'lacuna gap missing text'),
('w_humanities_C1_33','poetics','/poʊˈetɪks/','noun','시학, 시 이론','The theory and practice of literary composition.','Aristotle''s {poetics} defined tragedy for centuries.','아리스토텔레스의 시학은 수 세기 동안 비극을 정의했어요.','poetics','C1','humanities',2,'poetics theory aristotle literary'),
('w_humanities_C1_34','deixis','/ˈdaɪksɪs/','noun','직시(直示), 지시 표현','Words or phrases that require contextual information to interpret.','Understanding {deixis} is key to analyzing a dramatic monologue.','직시 표현을 이해하는 것은 극적 독백 분석의 핵심이에요.','deixis','C1','humanities',3,'deixis context language reference'),
('w_humanities_C1_35','ekphrasis','/ˈekfrəsɪs/','noun','에크프라시스','A vivid verbal description of a visual work of art.','Keats'' Ode on a Grecian Urn is a famous example of {ekphrasis}.','키츠의 그리스 항아리에 부치는 송시는 에크프라시스의 유명한 예예요.','ekphrasis','C1','humanities',3,'ekphrasis art description poem visual');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C2_01','logocentrism','/ˈloʊɡoʊˌsentrɪzəm/','noun','로고스 중심주의','Derrida''s term for the privileging of speech over writing in Western thought.','The entire deconstructive project aims to displace {logocentrism}.','해체주의 프로젝트 전체는 로고스 중심주의를 대체하는 것을 목표로 해요.','logocentrism','C2','humanities',2,'logocentrism derrida language text'),
('w_humanities_C2_02','différance','/ˌdiːfəˈrɑːns/','noun','디페랑스','Derrida''s neologism combining "differ" and "defer" to describe the endless play of signification.','The concept of {différance} undermines the possibility of fixed meaning.','디페랑스 개념은 고정된 의미의 가능성을 허물어요.','différance','C2','humanities',2,'différance derrida meaning sign'),
('w_humanities_C2_03','palimpsest','/ˈpælɪmpsest/','noun','팔림프세스트 (겹쳐 쓴 양피지)','A manuscript on which writing has been effaced and replaced; a text with layered meanings.','The novel reads as a cultural {palimpsest}, each layer revealing a different history.','소설은 문화적 팔림프세스트처럼 읽히며, 각 층이 다른 역사를 드러내요.','palimpsest','C2','humanities',2,'palimpsest layers text history'),
('w_humanities_C2_04','bricolage','/ˌbrɪkəˈlɑːʒ/','noun','브리콜라주','The construction of a work from diverse available resources.','Postmodern art is characterized by its use of {bricolage}.','포스트모던 예술은 브리콜라주 사용이 특징이에요.','bricolage','C2','humanities',2,'bricolage collage assembly postmodern'),
('w_humanities_C2_05','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','헤테로글로시아','Bakhtin''s term for the coexistence of multiple voices within a single text.','The polyphonic novel depends on {heteroglossia} to generate meaning.','다성 소설은 의미를 생성하기 위해 헤테로글로시아에 의존해요.','heteroglossia','C2','humanities',3,'heteroglossia bakhtin voices novel'),
('w_humanities_C2_06','chronotope','/ˈkrɒnətəʊp/','noun','크로노토프 (시공간 형상)','Bakhtin''s term for the way time and space are represented in literature.','The road {chronotope} is common in adventure narratives.','도로 크로노토프는 모험 서사에서 흔히 나타나요.','chronotope','C2','humanities',3,'chronotope time space bakhtin'),
('w_humanities_C2_07','defamiliarization','/ˌdiːfəˌmɪliəraɪˈzeɪʃən/','noun','낯설게 하기 (오스트라네니에)','Shklovsky''s term for making familiar things seem strange to renew perception.','Kafka achieves {defamiliarization} by treating the absurd as mundane.','카프카는 부조리한 것을 평범하게 다룸으로써 낯설게 하기를 달성해요.','defamiliarization','C2','humanities',2,'defamiliarization shklovsky strange form'),
('w_humanities_C2_08','rhizome','/ˈraɪzoʊm/','noun','리좀 (철학 개념)','Deleuze and Guattari''s model of culture as non-hierarchical and multi-directional.','The internet can be understood as a cultural {rhizome}.','인터넷은 문화적 리좀으로 이해될 수 있어요.','rhizome','C2','humanities',3,'rhizome network deleuze structure'),
('w_humanities_C2_09','hypertext','/ˈhaɪpərtekst/','noun','하이퍼텍스트','Text containing links to other texts; also a postmodern narrative form.','{Hypertext} fiction challenges linear reading conventions.','하이퍼텍스트 소설은 선형적 독해 관습에 도전해요.','hypertext','C2','humanities',2,'hypertext digital link narrative'),
('w_humanities_C2_10','episteme','/ˈepɪstiːm/','noun','에피스테메 (푸코 개념)','The underlying structure of knowledge that defines what counts as truth in an era.','Each historical period has its own {episteme} governing what can be known.','각 역사적 시기에는 알 수 있는 것을 지배하는 에피스테메가 있어요.','episteme','C2','humanities',2,'episteme knowledge foucault era'),
('w_humanities_C2_11','abjection','/æbˈdʒekʃən/','noun','아브젝시옹 (크리스테바 개념)','Julia Kristeva''s concept of the horror produced by the breakdown of the self/other boundary.','Gothic literature often exploits {abjection} to unsettle the reader.','고딕 문학은 종종 독자를 불안하게 하기 위해 아브젝시옹을 이용해요.','abjection','C2','humanities',3,'abjection kristeva horror body'),
('w_humanities_C2_12','pharmakon','/ˈfɑːrməkɒn/','noun','파르마콘 (데리다 개념)','Derrida''s term for writing as both remedy and poison, undoing binary oppositions.','Plato''s {pharmakon} is central to Derrida''s critique of Western philosophy.','플라톤의 파르마콘은 서양 철학에 대한 데리다의 비판의 핵심이에요.','pharmakon','C2','humanities',3,'pharmakon derrida writing remedy'),
('w_humanities_C2_13','suture','/ˈsuːtʃər/','noun','봉합 (영화·문학 이론)','A psychoanalytic film theory term for the process by which subjects are bound into discourse.','Narrative {suture} positions the reader as a unified subject.','서사적 봉합은 독자를 통합된 주체로 자리매김해요.','suture','C2','humanities',3,'suture narrative subject theory'),
('w_humanities_C2_14','apophenia','/ˌæpəˈfiːniə/','noun','아포페니아 (무관한 것의 연결)','The tendency to perceive meaningful connections between unrelated things.','Postmodern readings may tip into {apophenia} if taken too far.','포스트모던 독해는 너무 나가면 아포페니아에 빠질 수 있어요.','apophenia','C2','humanities',3,'apophenia pattern meaning connection'),
('w_humanities_C2_15','parataxis','/ˌpærəˈtæksɪs/','noun','병렬 구문 배열','The placing of clauses or phrases one after another without coordinating or subordinating connectives.','Hemingway''s famous style relies heavily on {parataxis}.','헤밍웨이의 유명한 문체는 병렬 구문에 크게 의존해요.','parataxis','C2','humanities',2,'parataxis syntax style sentence'),
('w_humanities_C2_16','catachresis','/ˌkætəˈkriːsɪs/','noun','카타크레시스 (무리한 비유)','The use of a word in an inappropriate context; a strained or mixed metaphor.','Spivak uses {catachresis} to reclaim and subvert colonial concepts.','스피박은 식민지 개념을 재전유하고 전복하기 위해 카타크레시스를 사용해요.','catachresis','C2','humanities',3,'catachresis metaphor misuse language'),
('w_humanities_C2_17','prolepsis','/proʊˈlepsɪs/','noun','프롤렙시스 (예기)','A narrative technique anticipating a future event; also a rhetorical device.','The opening sentence works as a subtle {prolepsis} for the ending.','첫 문장은 결말의 미묘한 프롤렙시스로 기능해요.','prolepsis','C2','humanities',3,'prolepsis anticipation future narrative'),
('w_humanities_C2_18','synecdoche','/sɪˈnekdəki/','noun','제유법','A figure of speech where a part represents the whole or vice versa.','The phrase "hired hands" is a classic example of {synecdoche}.','hired hands라는 표현은 제유법의 고전적인 예예요.','synecdoche','C2','humanities',2,'synecdoche figure speech part whole'),
('w_humanities_C2_19','diegesis','/ˌdaɪəˈdʒiːsɪs/','noun','디에게시스 (서사 세계)','The narrative world in which the story takes place; also the act of telling.','Music that exists within the story''s world is called diegetic; outside it, non-{diegesis}.','이야기 세계 안에 존재하는 음악은 디에제틱, 밖은 비디에게시스라고 해요.','diegesis','C2','humanities',3,'diegesis narrative world story'),
('w_humanities_C2_20','metalepsis','/ˌmetəˈlepsɪs/','noun','메탈렙시스 (서사 층위 침범)','The transgression of narrative levels, e.g. a character addressing the reader.','When the protagonist winks at the reader, it is a form of {metalepsis}.','주인공이 독자에게 윙크할 때 메탈렙시스의 한 형태예요.','metalepsis','C2','humanities',3,'metalepsis narrative metafiction layers'),
('w_humanities_C2_21','enargeia','/ɛˈnɑːrdʒiə/','noun','에나르게이아 (생생한 묘사)','Vivid, lively description that creates a mental picture for the audience.','The battle scene achieves powerful {enargeia} through sensory detail.','전투 장면은 감각적 디테일을 통해 강력한 에나르게이아를 달성해요.','enargeia','C2','humanities',3,'enargeia vivid description rhetoric'),
('w_humanities_C2_22','dispositio','/ˌdɪspəˈzɪtiːoʊ/','noun','디스포지티오 (수사적 배열)','The arrangement and structuring of a rhetorical composition.','Classical oratory depends on {dispositio} to guide the audience.','고전 수사는 청중을 이끌기 위해 디스포지티오에 의존해요.','dispositio','C2','humanities',3,'dispositio rhetoric structure arrangement'),
('w_humanities_C2_23','anagnorisis','/ˌænæɡˈnɒrɪsɪs/','noun','아나그노리시스 (재인식)','The moment of recognition or discovery in a drama or narrative.','The {anagnorisis} in Oedipus Rex is among the most devastating in literature.','오이디푸스 왕의 아나그노리시스는 문학에서 가장 충격적인 것 중 하나예요.','anagnorisis','C2','humanities',2,'anagnorisis recognition moment drama'),
('w_humanities_C2_24','peripeteia','/ˌperɪpɪˈteɪə/','noun','페리페테이아 (반전)','A sudden reversal of fortune in a narrative, especially tragedy.','The {peripeteia} in Hamlet occurs when the hero kills Polonius by mistake.','햄릿의 페리페테이아는 주인공이 실수로 폴로니우스를 죽일 때 일어나요.','peripeteia','C2','humanities',2,'peripeteia reversal tragedy drama'),
('w_humanities_C2_25','deus ex machina','/ˌdeɪʊs eks ˈmɑːkɪnə/','noun','데우스 엑스 마키나','An unexpected power or event saving a seemingly hopeless situation.','Critics dismissed the ending as a lazy {deus ex machina}.','비평가들은 그 결말을 게으른 데우스 엑스 마키나로 일축했어요.','deus ex machina','C2','humanities',2,'deus ex machina plot rescue ending'),
('w_humanities_C2_26','acousmatic','/ˌækuːzˈmætɪk/','adjective','아쿠스마틱 (보이지 않는 소리)','Referring to sound heard without a visible source; extended to voice in narrative.','The narrator''s {acousmatic} presence creates an eerie atmosphere.','화자의 아쿠스마틱 존재감이 섬뜩한 분위기를 만들어요.','acousmatic','C2','humanities',3,'acousmatic sound voice invisible'),
('w_humanities_C2_27','locution','/loʊˈkjuːʃən/','noun','발화 행위 (화행론)','In speech act theory, the utterance of a statement.','Austin distinguished {locution} from illocution and perlocution.','오스틴은 발화 행위를 발화 수반 행위와 발화 효과 행위로 구별했어요.','locution','C2','humanities',3,'locution speech act language theory'),
('w_humanities_C2_28','apophasis','/əˈpɒfəsɪs/','noun','아포파시스 (부정을 통한 언급)','A rhetorical device where something is mentioned by denying it will be mentioned.','Using {apophasis}, he condemned the scandal without naming it.','아포파시스를 사용해 그는 스캔들을 명명하지 않고 비난했어요.','apophasis','C2','humanities',3,'apophasis rhetoric denial mention'),
('w_humanities_C2_29','hypotaxis','/ˌhaɪpəˈtæksɪs/','noun','종속 구문 배열','The use of subordinating conjunctions and clauses to show complex relationships.','Henry James''s prose is famous for its elaborate {hypotaxis}.','헨리 제임스의 산문은 정교한 종속 구문으로 유명해요.','hypotaxis','C2','humanities',3,'hypotaxis syntax complex sentence'),
('w_humanities_C2_30','cathartic','/kəˈθɑːrtɪk/','adjective','카타르시스를 주는','Providing psychological relief through the open expression of strong emotion.','The final scene is intensely {cathartic} for the audience.','마지막 장면은 관객에게 강렬한 카타르시스를 줘요.','cathartic','C2','humanities',2,'cathartic release emotion healing'),
('w_humanities_C2_31','anxious object','/ˈæŋkʃəs ˈɒbdʒɪkt/','noun','불안한 대상 (미술 비평)','Harold Rosenberg''s term for art that questions its own status as art.','The novel functions as an {anxious object}, unsure of its own genre.','소설은 자신의 장르에 대해 불확실한 불안한 대상으로 기능해요.','anxious object','C2','humanities',3,'anxious object art form genre'),
('w_humanities_C2_32','perlocution','/ˌpɜːrləˈkjuːʃən/','noun','발화 효과 행위','The effect of an utterance on the listener beyond its literal meaning.','Great oratory achieves its goals through {perlocution}.','훌륭한 웅변은 발화 효과 행위를 통해 목표를 달성해요.','perlocution','C2','humanities',3,'perlocution effect speech language'),
('w_humanities_C2_33','dialogism','/daɪˈæləɡɪzəm/','noun','대화주의 (바흐친)','Bakhtin''s theory that all utterances are inherently dialogic.','{Dialogism} challenges the notion of the solitary author.','대화주의는 고독한 작가의 개념에 도전해요.','dialogism','C2','humanities',2,'dialogism bakhtin dialogue intertextual'),
('w_humanities_C2_34','negative capability','/ˌneɡətɪv keɪpəˈbɪlɪti/','noun','부정적 수용 능력 (키츠)','Keats''s term for the ability to remain in uncertainty without reaching for fact or reason.','Great poets possess the {negative capability} to dwell in mystery.','위대한 시인은 신비 속에 머무는 부정적 수용 능력을 지녀요.','negative capability','C2','humanities',2,'negative capability keats poetry uncertainty'),
('w_humanities_C2_35','uncanny','/ʌnˈkæni/','adjective / noun','언캐니 (낯설면서 친숙한 공포)','Freud''s concept of the strangely familiar; the disturbing feeling caused by something both familiar and strange.','The gothic mansion creates a profound sense of the {uncanny}.','고딕 저택은 깊은 언캐니 감각을 만들어요.','uncanny','C2','humanities',2,'uncanny freud strange familiar horror');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_A1_01','Have you read any good books lately?','최근에 좋은 책 읽었어요?','read any good books','lately는 "최근에"라는 의미로 현재완료와 잘 어울려요.','독서 화제','A1','humanities','pattern',NULL,1),
('s_humanities_A1_02','What is your favorite book?','가장 좋아하는 책이 뭐예요?','your favorite book','What is your favorite ~?는 상대의 취향을 묻는 가장 기본적인 패턴이에요.','취향 묻기','A1','humanities','pattern',NULL,2),
('s_humanities_A1_03','I really like this story.','이 이야기가 정말 좋아요.','really like this story','really를 넣으면 감정을 더 강하게 표현할 수 있어요.','감상 표현','A1','humanities','pattern',NULL,3),
('s_humanities_A1_04','Can you tell me the name of the book?','책 제목을 알려줄 수 있어요?','tell me the name','Can you ~?는 A1 수준에서 가장 자연스러운 요청 표현이에요.','제목 묻기','A1','humanities','pattern',NULL,4),
('s_humanities_A1_05','I want to read more books in English.','영어로 된 책을 더 읽고 싶어요.','read more books in English','I want to ~는 희망과 목표를 간단하게 표현하는 패턴이에요.','학습 목표','A1','humanities','pattern',NULL,5),
('s_humanities_A1_06','This poem is very beautiful.','이 시는 정말 아름다워요.','very beautiful','This ~ is very ~. 구조는 감상을 간결하게 전달해요.','시 감상','A1','humanities','pattern',NULL,6),
('s_humanities_A1_07','Do you like to read stories?','이야기 읽는 걸 좋아하세요?','Do you like to read','Do you like to ~?는 취미를 묻는 가장 쉬운 표현이에요.','취미 묻기','A1','humanities','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_A2_01','Who is your favorite author and why?','가장 좋아하는 작가는 누구이고 왜 그런가요?','favorite author and why','and why?를 붙이면 단순한 정보 교환을 넘어 의견 공유를 유도해요.','작가 추천','A2','humanities','pattern',NULL,8),
('s_humanities_A2_02','I enjoy reading mystery novels.','저는 추리 소설 읽는 걸 즐겨요.','enjoy reading mystery novels','enjoy + -ing는 취미 표현의 핵심 패턴이에요.','장르 표현','A2','humanities','pattern',NULL,9),
('s_humanities_A2_03','This book is based on a true story.','이 책은 실화를 바탕으로 했어요.','based on a true story','based on ~은 영화·책 소개에서 매우 자주 쓰여요.','책 소개','A2','humanities','pattern',NULL,10),
('s_humanities_A2_04','Have you heard of this author before?','이 작가에 대해 들어본 적 있어요?','Have you heard of','Have you heard of ~?는 상대의 지식을 확인하는 자연스러운 표현이에요.','작가 소개','A2','humanities','pattern',NULL,11),
('s_humanities_A2_05','What kind of books do you usually read?','보통 어떤 종류의 책을 읽으세요?','What kind of books','What kind of ~?는 종류나 유형을 묻는 범용 패턴이에요.','장르 묻기','A2','humanities','pattern',NULL,12),
('s_humanities_A2_06','I prefer historical fiction to fantasy.','저는 판타지보다 역사 소설을 더 좋아해요.','prefer ~ to ~','prefer A to B 패턴으로 두 가지를 자연스럽게 비교할 수 있어요.','장르 비교','A2','humanities','pattern',NULL,13),
('s_humanities_A2_07','The main character in this novel is very interesting.','이 소설의 주인공이 매우 흥미로워요.','main character ~ very interesting','The main character is ~로 인물을 소개하는 기본 표현이에요.','인물 소개','A2','humanities','pattern',NULL,14);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_B1_01','The author uses symbolism to convey the theme of loss.','작가는 상실의 주제를 전달하기 위해 상징주의를 사용해요.','uses symbolism to convey','use A to do B 패턴은 수단과 목적을 연결하는 핵심 분석 표현이에요.','문학 분석','B1','humanities','pattern',NULL,15),
('s_humanities_B1_02','From whose perspective is the story told?','이야기는 누구의 관점에서 서술되나요?','From whose perspective','From whose perspective is ~?는 서술 시점을 묻는 정확한 표현이에요.','서술 시점','B1','humanities','pattern',NULL,16),
('s_humanities_B1_03','How does the setting influence the characters'' behavior?','배경이 등장인물들의 행동에 어떤 영향을 미치나요?','setting influence the characters'' behavior','How does X influence Y? 패턴은 원인-결과 관계를 탐구해요.','배경 분석','B1','humanities','pattern',NULL,17),
('s_humanities_B1_04','What do you think the writer is trying to say?','작가가 무엇을 말하려 한다고 생각하세요?','what the writer is trying to say','What do you think ~?는 독자의 해석을 이끌어내는 토론 유도 표현이에요.','주제 토론','B1','humanities','pattern',NULL,18),
('s_humanities_B1_05','The conflict between tradition and modernity runs throughout the novel.','전통과 근대성 사이의 갈등이 소설 전반에 걸쳐 흐르고 있어요.','conflict between ~ runs throughout','run throughout은 "전반에 걸쳐 이어지다"는 뜻의 문학 분석 필수 표현이에요.','주제 분석','B1','humanities','pattern',NULL,19),
('s_humanities_B1_06','I found the narrator unreliable because his account kept changing.','화자의 설명이 계속 바뀌어서 신뢰하기 어렵다고 느꼈어요.','narrator unreliable ~ kept changing','kept + -ing는 반복적인 행동을 묘사하는 자연스러운 패턴이에요.','화자 분석','B1','humanities','pattern',NULL,20),
('s_humanities_B1_07','Can you give an example from the text to support your idea?','당신의 생각을 뒷받침할 텍스트에서의 예시를 들어줄 수 있나요?','give an example from the text to support','give an example to support ~는 증거 기반 토론의 핵심 요청 표현이에요.','근거 요청','B1','humanities','pattern',NULL,21);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_B2_01','The irony lies in the gap between what the narrator says and what actually happens.','아이러니는 화자가 말하는 것과 실제로 일어나는 것 사이의 간극에 있어요.','irony lies in the gap between','The irony lies in ~은 아이러니를 정밀하게 분석하는 비평 표현이에요.','아이러니 분석','B2','humanities','pattern',NULL,22),
('s_humanities_B2_02','One could argue that the novel is more of an allegory than a realist text.','이 소설은 사실주의 텍스트라기보다 알레고리에 가깝다고 주장할 수 있어요.','One could argue that','One could argue that ~은 학술 에세이와 비평에서 쓰는 격식 있는 주장 패턴이에요.','비평 주장','B2','humanities','pattern',NULL,23),
('s_humanities_B2_03','The motif of water recurs throughout the text, suggesting purification.','물의 모티프가 텍스트 전반에 반복되며 정화를 암시해요.','motif ~ recurs throughout ~ suggesting','recurs throughout ~ suggesting은 모티프 분석의 정형화된 표현이에요.','모티프 분석','B2','humanities','pattern',NULL,24),
('s_humanities_B2_04','The subtext reveals a deep anxiety about social class.','서브텍스트는 사회 계층에 대한 깊은 불안을 드러내요.','subtext reveals a deep anxiety about','The subtext reveals ~ 패턴은 텍스트의 숨겨진 층위를 드러낼 때 써요.','서브텍스트','B2','humanities','pattern',NULL,25),
('s_humanities_B2_05','Reading the novel against its historical context changes how we interpret the ending.','소설을 역사적 맥락에 비추어 읽으면 결말 해석이 달라져요.','Reading ~ against its historical context','reading X against Y 구조는 텍스트를 외부 맥락과 연결하는 비평 방법이에요.','맥락 비평','B2','humanities','pattern',NULL,26),
('s_humanities_B2_06','The satirical tone forces the reader to question assumptions they might otherwise take for granted.','풍자적 어조는 독자로 하여금 당연하게 여길 수 있는 전제를 의심하게 만들어요.','satirical tone forces the reader to question','force the reader to ~는 텍스트가 독자에게 미치는 효과를 설명하는 표현이에요.','풍자 분석','B2','humanities','pattern',NULL,27),
('s_humanities_B2_07','The paradox at the heart of the novel is that freedom leads to isolation.','소설의 핵심에 있는 역설은 자유가 고립으로 이어진다는 것이에요.','paradox at the heart of the novel','at the heart of ~은 핵심 주제나 역설을 강조하는 비평 표현이에요.','역설 분석','B2','humanities','pattern',NULL,28);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_C1_01','A hermeneutic approach asks not what the text means, but how meaning is produced.','해석학적 접근은 텍스트가 무엇을 의미하는지가 아니라 의미가 어떻게 생산되는지를 묻죠.','hermeneutic approach asks not ~ but how','not ~ but how 구조는 관점의 전환을 명확히 드러내는 학술 표현이에요.','해석학 논의','C1','humanities','pattern',NULL,29),
('s_humanities_C1_02','Through a semiotic lens, the white dress signifies far more than purity.','기호학적 렌즈를 통하면, 흰 드레스는 순결 이상의 훨씬 많은 것을 의미해요.','Through a semiotic lens ~ signifies far more than','through a ~ lens는 이론적 프레임으로 분석함을 나타내는 표현이에요.','기호학 분석','C1','humanities','pattern',NULL,30),
('s_humanities_C1_03','Intertextuality suggests that no text is fully autonomous; all writing responds to what came before.','상호텍스트성은 완전히 자율적인 텍스트는 없으며, 모든 글쓰기는 이전 것에 반응한다는 것을 시사해요.','Intertextuality suggests that no text is fully autonomous','no text is fully autonomous는 상호텍스트성의 핵심 명제를 요약해요.','상호텍스트성','C1','humanities','pattern',NULL,31),
('s_humanities_C1_04','Deconstruction does not destroy meaning; it reveals the instability that was always already there.','해체주의는 의미를 파괴하지 않고, 항상 이미 그곳에 있던 불안정성을 드러내요.','always already there','always already는 데리다 이론의 핵심 표현으로 현재 안에 과거가 내포됨을 나타내요.','해체주의 이론','C1','humanities','pattern',NULL,32),
('s_humanities_C1_05','Phenomenological criticism foregrounds the reader''s lived experience of the text.','현상학적 비평은 텍스트에 대한 독자의 생생한 경험을 전면에 부각시켜요.','foregrounds the reader''s lived experience','foreground는 무언가를 중심으로 가져온다는 문학 이론 용어예요.','현상학 비평','C1','humanities','pattern',NULL,33),
('s_humanities_C1_06','Bakhtin''s concept of polyphony challenges the idea of a single authoritative voice in the novel.','바흐친의 다성 개념은 소설에서 단일하고 권위적인 목소리라는 생각에 도전해요.','polyphony challenges the idea of a single authoritative voice','challenge the idea of ~는 지배적 개념을 문제 삼는 학술 표현이에요.','다성 이론','C1','humanities','pattern',NULL,34),
('s_humanities_C1_07','The sublime, as Burke defines it, involves a blend of terror and awe that exceeds rational comprehension.','버크가 정의한 숭고함은 이성적 이해를 초월하는 공포와 경외의 혼합을 포함해요.','involves a blend of ~ that exceeds rational comprehension','exceed rational comprehension은 숭고 미학을 설명하는 핵심 구절이에요.','숭고 미학','C1','humanities','pattern',NULL,35);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_C2_01','Différance operates as the ungraspable condition of possibility for all meaning.','디페랑스는 모든 의미의 가능성에 대한 파악 불가능한 조건으로 작동해요.','operates as the ungraspable condition of possibility','operate as ~는 어떤 개념이 어떤 역할을 하는지 설명하는 학술 표현이에요.','해체 이론','C2','humanities','pattern',NULL,36),
('s_humanities_C2_02','The palimpsest as a metaphor invites us to read the text''s silences as much as its statements.','팔림프세스트를 은유로 취하면, 텍스트의 진술만큼 침묵도 읽으라는 초대가 돼요.','invites us to read the text''s silences as much as','as much as는 두 요소를 동등하게 취급하라는 요청을 나타내요.','팔림프세스트 이론','C2','humanities','pattern',NULL,37),
('s_humanities_C2_03','Defamiliarization, according to the Russian Formalists, is the very purpose of literary language.','러시아 형식주의자들에 따르면, 낯설게 하기는 문학적 언어의 바로 그 목적이에요.','the very purpose of literary language','the very ~는 강조 표현으로, 그것 자체가 핵심임을 나타내요.','형식주의 이론','C2','humanities','pattern',NULL,38),
('s_humanities_C2_04','As a rhizome, the text resists any single origin or fixed endpoint of meaning.','리좀으로서 텍스트는 어떠한 단일한 기원이나 고정된 의미의 종착점에도 저항해요.','resists any single origin or fixed endpoint','resist any single ~는 다원성과 열린 구조를 강조할 때 쓰는 표현이에요.','리좀 이론','C2','humanities','pattern',NULL,39),
('s_humanities_C2_05','Heteroglossia ensures that the novel can never be reduced to a single ideological position.','헤테로글로시아는 소설이 결코 단일한 이데올로기적 입장으로 환원될 수 없음을 보장해요.','can never be reduced to a single ideological position','be reduced to ~는 복잡성을 단순화하는 환원주의에 저항할 때 쓰는 표현이에요.','다성 이론','C2','humanities','pattern',NULL,40),
('s_humanities_C2_06','The chronotope of the threshold marks a liminal space where identity is suspended between states.','문지방의 크로노토프는 정체성이 두 상태 사이에 유예되는 경계적 공간을 표시해요.','marks a liminal space where identity is suspended between states','liminal space ~ suspended between states는 경계 공간의 특성을 묘사하는 핵심 표현이에요.','크로노토프 분석','C2','humanities','pattern',NULL,41),
('s_humanities_C2_07','Negative capability, for Keats, is not a weakness but the poet''s supreme capacity to inhabit uncertainty without discomfort.','키츠에게 부정적 수용 능력은 약점이 아니라 불편 없이 불확실성 안에 머무는 시인의 최고 능력이에요.','not a weakness but the poet''s supreme capacity to inhabit uncertainty','inhabit uncertainty는 불확실성을 견디는 것이 아닌 그 안에 사는 것을 나타내는 키츠 핵심 표현이에요.','낭만 시학','C2','humanities','pattern',NULL,42);
